// Подготовка данных сессии и очистка входа
const message = $input.first().json.message;
const chatId = message.chat.id;
const text = message.text || '';
const userId = message.from.id;

// Проверка на пустое сообщение или команду старта без контекста
if (!text.trim() && !message.new_chat_members) {
  return [{ json: { skip: true, reason: 'empty_message' } }];
}

// Формирование единого sessionId для памяти
const sessionId = `chat_${chatId}_user_${userId}`;

return [{
  json: {
    chatId,
    userId,
    text,
    sessionId,
    timestamp: new Date().toISOString(),
    input: {
      role: 'user',
      content: text
    }
  }
}];

// === MEMORY HUB (SHARED) ===
// Централизованное управление памятью сессий
// В production заменить на вызов Redis/PostgreSQL через HTTP Request

const chatId = $input.first().json.chatId;
const userMessage = $input.first().json.message;
const timestamp = new Date().toISOString();

// Ключ сессии
const sessionKey = `session:${chatId}`;

// Имитация хранилища сессий (в production использовать $getWorkflowStaticData или внешнюю БД)
let session = {};

// Попытка получить существующую сессию из статических данных workflow
try {
  const staticData = $getWorkflowStaticData();
  if (staticData.sessions && staticData.sessions[sessionKey]) {
    session = staticData.sessions[sessionKey];
  } else {
    // Инициализация новой сессии
    session = {
      chatId: chatId,
      createdAt: timestamp,
      updatedAt: timestamp,
      messageCount: 0,
      history: [],
      context: {
        currentAgent: 'orchestrator',
        lastIntent: null,
        skills: ['calendar', 'default']
      },
      metadata: {
        language: 'ru',
        timezone: 'Asia/Yekaterinburg'
      }
    };
  }
} catch (error) {
  // При ошибке создаём новую сессию
  session = {
    chatId: chatId,
    createdAt: timestamp,
    updatedAt: timestamp,
    messageCount: 0,
    history: [],
    context: {
      currentAgent: 'orchestrator',
      lastIntent: null,
      skills: ['calendar', 'default']
    },
    metadata: {
      language: 'ru',
      timezone: 'Asia/Yekaterinburg'
    }
  };
}

// Добавляем сообщение пользователя в историю
session.history.push({
  role: 'user',
  content: userMessage,
  timestamp: timestamp
});

// Ограничиваем историю последними 10 сообщениями
if (session.history.length > 10) {
  session.history = session.history.slice(-10);
}

session.messageCount += 1;
session.updatedAt = timestamp;

// Сохраняем сессию в статические данные workflow
try {
  const staticData = $getWorkflowStaticData();
  if (!staticData.sessions) {
    staticData.sessions = {};
  }
  staticData.sessions[sessionKey] = session;
} catch (error) {
  console.error('Failed to save session to static data:', error.message);
}

return [{
  json: {
    ...$input.first().json,
    sessionId: sessionKey,
    session: session,
    messageHistory: session.history,
    sessionContext: session.context,
    metadata: session.metadata,
    isNewSession: session.messageCount === 1
  }
}];

// Объединение результатов от разных веток с очисткой от JSON-разметки
let responseText = '';

// Получаем входные данные
const input = $input.first().json;

// Функция для извлечения чистого текста из различных форматов
function extractContent(data) {
  if (!data) return '';

  // Если строка - пробуем распарсить как JSON
  if (typeof data === 'string') {
    try {
      const parsed = JSON.parse(data);
      // Возвращаем только полезное содержимое, убираем action
      return parsed.response || parsed.content || parsed.text || parsed.message || data;
    } catch (e) {
      // Если не JSON - чистим от возможных остатков JSON-синтаксиса
      return data
        .replace(/^\s*\{\s*"action"\s*:\s*"[^"]*"\s*,\s*"response"\s*:\s*"/, '') // Удаляем {"action": "...", "response": "
        .replace(/"\s*\}\s*$/, '') // Удаляем завершающие "}
        .replace(/\\"/g, '"') // Раэкранируем кавычки
        .trim();
    }
  }

  // Если объект - извлекаем content/response
  if (typeof data === 'object') {
    // Исключаем технические поля
    const { action, confidence, forward_to, ...rest } = data;
    return rest.response || rest.content || rest.text || rest.message || JSON.stringify(rest);
  }

  return String(data);
}

// Определяем источник ответа
if (input.choices?.[0]?.message?.content) {
  // Стандартный формат OpenAI/Groq API
  responseText = extractContent(input.choices[0].message.content);
} else if (input.output) {
  // Ответ от General Chat или других агентов
  responseText = extractContent(input.output);
} else if (input.response) {
  // Ответ от LangChain Agent (Calendar)
  responseText = extractContent(input.response);
} else if (input.content) {
  // Прямой формат content
  responseText = extractContent(input.content);
} else {
  // Fallback
  responseText = 'Произошла ошибка обработки запроса.';
}

// Финальная очистка от технических префиксов, если остались
responseText = responseText
  .replace(/^\s*{\s*"action"\s*:\s*"respond"\s*,\s*"response"\s*:\s*"/i, '')
  .replace(/^\s*{\s*"action"\s*:\s*"route_calendar"\s*,\s*"response"\s*:\s*"/i, '')
  .replace(/"\s*}\s*$/g, '')
  .replace(/\\"/g, '"')
  .replace(/^["']|["']$/g, '')
  .trim();

// Если после очистки пусто - используем fallback
if (!responseText) {
  responseText = 'Не удалось обработать ответ агента.';
}

return [{
  json: {
    chatId: $('Init Session & Validate').first().json.chatId,
    text: responseText,
    originalInput: $('Init Session & Validate').first().json.text
  }
}];

// Обработка ошибки: отправка сообщения пользователю
const chatId = $('Init Session & Validate').first()?.json?.chatId || $json.chatId;
const errorMsg = '⚠️ Произошла внутренняя ошибка. Попробуйте позже.';

return [{
  json: {
    chatId: chatId,
    text: errorMsg
  }
}];

